def priority(job, proc_times, sequence):
    # Basic heuristic: prioritize shorter total processing time (SPT style)
    times = proc_times[job]
    total = 0
    for t in times:
        total += t
    score = -total

    # Slight bias towards smaller first-machine time to reduce front-loading
    if times:
        score += -times[0] * 0.1

    # Contextual tie-break with the last scheduled job, if available
    if sequence:
        last = sequence[-1]
        last_times = proc_times[last]
        if last_times:
            first_last = last_times[0]
            first_cur = times[0] if times else 0
            if first_last == first_cur:
                score += 0.5
            else:
                score += -abs(first_last - first_cur) * 0.05

    return score
